/** WASI binary from fixtures/wanix/echo_stdin.wat (regenerate with wat2wasm). */
const ECHO_STDIN_WASM_HEX =
  ''

function hextobytes(hex: string): Uint8Array {
  const out = new Uint8Array(hex.length / 2)
  for (let i = 0; i < out.length; i++) {
    out[i] = parseInt(hex.slice(i * 2, i * 2 + 2), 16)
  }
  return out
}

export const ECHO_STDIN_WASM_BYTES = hextobytes(ECHO_STDIN_WASM_HEX)

export const ECHO_STDIN_WASM_BYTE_LIST = [...ECHO_STDIN_WASM_BYTES]

export function createechostdinwasmfile(): File {
  return new File([new Uint8Array(ECHO_STDIN_WASM_BYTES)], 'echo_stdin.wasm', {
    type: 'application/wasm',
  })
}
